$LangCheckboxes  = @{}
$colW  = 240
$rowH  = 22
$col  = 0
$row  = 0
$keys  = @($LanguageData.Keys)

foreach ($code in $keys) {
  $entry  = $LanguageData[$code]
  $label  = "$code  -  $($entry.Name)"
  $cb  = New-DarkCheckbox -Text $label -Checked ([bool]$entry.Default)
  $cb.Location = New-Object System.Drawing.Point(($col * $colW + 4), ($row * $rowH + 2))
  $cb.Width  = $colW - 8
  $cb.AutoSize = $false
  $cb.Tag  = $code
  $LangPanel.Controls.Add($cb)
  $LangCheckboxes[$code] = $cb
  $row++
  if ($row -ge [math]::Ceiling($keys.Count / 3)) { $row = 0; $col++ }
}

